│                        "commands": "<<taskjs>>
(async () => {
  const ctx = window.SillyTavern?.getContext?.(); if (!ctx) return;
  const { saveSettingsDebounced } = await import('/script.js');
  const saveDebounced = saveSettingsDebounced || (()=>{});
  const saveNow = () => { try { ctx.saveSettings?.(); } catch {} };
  const $ = (id) => document.getElementById(id);
  const on = (el, ev, cb) => el && el.addEventListener(ev, cb);
  const h = (s) => String(s ?? '').replace(/[&<>"']/g, (m)=>({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[m]));
  const escTopSeg = (s) => String(s||'').replace(/\\/g,'\\\\').replace(/"/g,'\\"').replace(/\|/g,'｜');
  const rOut = (r)=>r==='system'?'sys':r, rIn=(r)=>r==='sys'?'system':r;
  const AUTHOR = '奈亚 xn1060';
  const TASK_NAME = 'NY-Sigon主程序';
  const PAIRED_TASK_NAME = 'NY-Sigon主程序';
  const EXT = 'LittleWhiteBox';
  const SESSION_ID = 2;
  const ex = (ctx.extensionSettings[EXT] ||= {});
  ex.apiByTask ||= {};
  ex.userPrefStoreByTask ||= {};
  ex.uiThemeByTask ||= {};
  const getTaskRef = () => window.XBTasks?.find?.(TASK_NAME, 'all') || null;
  const UI_THEME_MOON = 'moon';
  const UI_THEME_SUN = 'sun';
  const normalizeUiTheme = (v) => (String(v || '').toLowerCase() === UI_THEME_SUN ? UI_THEME_SUN : UI_THEME_MOON);
  const loadUiTheme = () => normalizeUiTheme(ex.uiThemeByTask[TASK_NAME]);
  const saveUiTheme = (theme) => {
    ex.uiThemeByTask[TASK_NAME] = normalizeUiTheme(theme);
    saveDebounced();
    saveNow();
  };
  const DEFAULT_REGEX_COMBINED = '/\\[([^\\s\\[\\]\\/]+)(?:\\s[^\\[\\]]*?)?\\]([\\s\\S]*?)\\[\\/\\1\\]/g';
  const extractTop = (cmd) => (String(cmd||'').match(/top="([\s\S]*?)"/)?.[1] || '').replace(/\\\\/g,'\\').replace(/\\"/g,'"');
  const parseTopToDraft = (topStr) => {
    const draft = { scaffold: [] }; if (!topStr) return draft;
    const toks = []; let buf='', d=0;
    for (const ch of String(topStr)) { if (ch==='{') d++; if (ch==='}') d=Math.max(0,d-1); if (ch===';' && d===0) { toks.push(buf.trim()); buf=''; } else buf+=ch; }
    if (buf.trim()) toks.push(buf.trim());
    let pos=0;
    for (const tk of toks) {
      const i=tk.indexOf('='); if (i<0) { pos++; continue; }
      const role = rIn(tk.slice(0,i).trim());
      const content = (tk.slice(i+1).trim().match(/^\{([\s\S]*)\}$/)?.[1]) ?? '';
      const hasWI = /\{\$worldInfo\}/.test(content);
      const hist = content.match(/\{\$history(\d+)\}/);
      const stripped = content.replace(/\{\$worldInfo\}/g,'').replace(/\{\$history\d+\}/g,'').trim();
      if (hist && stripped==='') {
        draft.specialIndex = pos;
        draft.specialRoleType = role;
        draft.historyDepth = parseInt(hist[1],10);
        if (hasWI) draft.includeWorldInfo = true;
      } else {
        draft.scaffold.push({ role, text: content });
      }
      pos++;
    }
    return draft;
  };
  const buildTopFromDraft = (d) => {
    if (!d) return '';
    const list = Array.isArray(d.scaffold) ? d.scaffold : [];
    const hasS = Number.isInteger(d.specialIndex);
    const depth = parseInt(d.historyDepth,10);
    const canS = hasS && typeof d.specialRoleType==='string' && Number.isFinite(depth);
    const wi = d.includeWorldInfo ? '{$worldInfo}' : '';
    const hist = Number.isFinite(depth) ? `{$history${depth}}` : '';
    const total = list.length + (hasS?1:0);
    const segs = [];
    for (let i=0, ri=0; i<total; i++){
      if (hasS && i===d.specialIndex) { if (canS) segs.push(`${rOut(d.specialRoleType)}={${escTopSeg(`${wi}${hist}`)}}`); continue; }
      const it = list[ri++]; if (it && it.role) segs.push(`${rOut(it.role)}={${escTopSeg(it.text)}}`);
    }
    return segs.join(';');
  };
  const parseCombinedRegex = (input) => {
    let raw = String(input || '').trim();
    if (!raw) return { pattern: '', flags: 'g' };
    if (raw.startsWith('/')) {
      const lastSlash = raw.lastIndexOf('/');
      if (lastSlash > 0) {
        const pattern = raw.slice(1, lastSlash);
        let flags = raw.slice(lastSlash + 1).replace(/[^gimsuy]/g, '');
        if (!flags.includes('g')) flags += 'g';
        return { pattern, flags };
      }
    }
    const lastBackslash = raw.lastIndexOf('\\');
    if (lastBackslash > -1 && lastBackslash < raw.length - 1) {
      const pattern = raw.slice(0, lastBackslash);
      let flags = raw.slice(lastBackslash + 1).replace(/[^gimsuy]/g, '');
      if (!flags.includes('g')) flags += 'g';
      return { pattern, flags };
    }
    return { pattern: raw, flags: 'g' };
  };

  const DEFAULT_USER_PREF = Object.freeze({ enabled: false, role: 'user', before: '<user_preference>', after: '</user_preference>', insertAt: null, text: '' });
  const normalizeUserPref = (v = {}) => {
    const src = (v && typeof v === 'object') ? v : {};
    const role = ['system', 'user', 'assistant'].includes(src.role) ? src.role : DEFAULT_USER_PREF.role;
    const insertAt = Number.isFinite(+src.insertAt) ? Math.max(0, Math.floor(+src.insertAt)) : null;
    const text = String(src.text ?? '');
    const enabled = !!src.enabled;
    let before = String(src.before ?? '').replace(/\r\n/g, '\n');
    let after = String(src.after ?? '').replace(/\r\n/g, '\n');
    let beforeHas = before.trim() !== '';
    let afterHas = after.trim() !== '';
    if (!beforeHas && !afterHas) {
      const tagRaw = String(src.tag ?? '').trim();
      const tag = tagRaw && /^[^\s<>"'\/=]+$/.test(tagRaw) ? tagRaw : '';
      if (tag) {
        before = `<${tag}>`;
        after = `</${tag}>`;
        beforeHas = true;
        afterHas = true;
      }
    }
    if (!beforeHas) before = DEFAULT_USER_PREF.before;
    if (!afterHas) after = DEFAULT_USER_PREF.after;
    return { enabled, role, before, after, insertAt, text };
  };
  const normalizeTplDraft = (draftLike) => {
    const d = (draftLike && typeof draftLike === 'object') ? draftLike : {};
    const scaffoldRaw = Array.isArray(d.scaffold) ? d.scaffold : [];
    const scaffold = scaffoldRaw.map((x) => ({ role: String(x?.role ?? 'user'), text: String(x?.text ?? '') }));
    const specialIndex = Number.isInteger(d.specialIndex) ? Math.max(0, Math.min(d.specialIndex, scaffold.length)) : undefined;
    const specialRoleType = typeof d.specialRoleType === 'string' ? d.specialRoleType : undefined;
    return { scaffold, specialIndex, specialRoleType, historyDepth: d.historyDepth, includeWorldInfo: !!d.includeWorldInfo };
  };
  const buildUserPrefXml = (userPrefLike) => {
    const pref = normalizeUserPref(userPrefLike);
    if (!pref.enabled) return '';
    const body = String(pref.text || '').trim();
    if (!body) return '';
    return [pref.before, body, pref.after].join('\n');
  };
  const compileTplWithUserPref = (tplRawLike, userPrefLike) => {
    const tplRaw = normalizeTplDraft(tplRawLike);
    const userPref = normalizeUserPref(userPrefLike);
    const xml = buildUserPrefXml(userPref);
    if (!xml) return tplRaw;

    const hasS = Number.isInteger(tplRaw.specialIndex);
    const total = tplRaw.scaffold.length + (hasS ? 1 : 0);
    const insertAt = Number.isInteger(userPref.insertAt) ? Math.max(0, Math.min(userPref.insertAt, total)) : total;
    const scaffoldInsertIndex = !hasS ? insertAt : (insertAt <= tplRaw.specialIndex ? insertAt : insertAt - 1);

    const scaffold = tplRaw.scaffold.slice();
    scaffold.splice(scaffoldInsertIndex, 0, { role: userPref.role, text: xml });
    const specialIndex = hasS && insertAt <= tplRaw.specialIndex ? tplRaw.specialIndex + 1 : tplRaw.specialIndex;
    return { ...tplRaw, scaffold, specialIndex };
  };
  const loadCfg = () => {
    const ref = getTaskRef();
    const t = ref?.task;
    const ns = t?.x?.LittleWhiteBox || {};
    const combined = DEFAULT_REGEX_COMBINED;
    const clean = { anchors: ['</think>'], blockTags: ['statusblock','options','other'], stripComments: true };
    const gen = (ns.gen && typeof ns.gen === 'object') ? ns.gen : {};
    return t ? {
      enabled: !t.disabled,
      interval: t.interval ?? 0,
      timing: t.triggerTiming || 'after_ai',
      floorType: t.floorType || 'all',
      commands: String(t.commands || ''),
      tpl: ns.tpl || null,
      tplRaw: ns.tplRaw || null,
      regexCombined: combined,
      clean,
      gen,
      userPref: ns.userPref || null
    } : {
      enabled:false, interval:0, timing:'after_ai', floorType:'all', commands:'', tpl:null, regexCombined: DEFAULT_REGEX_COMBINED,
      clean: { anchors: ['</think>'], blockTags: ['statusblock','options','other'], stripComments: true },
      gen: {},
      tplRaw: null,
      userPref: null
    };
  };
  const saveTaskAndTpl = async ({ enabled, interval, timing, floorType, draft, regexCombined, clean, gen, userPref }) => {
    const ref = getTaskRef();
    if (!ref) { toastr?.error?.(`Không tìm thấy tác vụ：${TASK_NAME}`); return; }
    const t = ref.task;
    const nsOld = t?.x?.LittleWhiteBox || {};
    const tplRaw = draft && typeof draft === 'object'
      ? normalizeTplDraft(draft)
      : (nsOld.tplRaw ? normalizeTplDraft(nsOld.tplRaw) : (nsOld.tpl ? normalizeTplDraft(nsOld.tpl) : null));
    const userPrefNext = normalizeUserPref((userPref && typeof userPref === 'object') ? userPref : nsOld.userPref);
    const tplCompiled = tplRaw ? compileTplWithUserPref(tplRaw, userPrefNext) : nsOld.tpl;
    const nsNext = {
      ...nsOld,
      tpl: tplCompiled || nsOld.tpl,
      tplRaw: tplRaw || nsOld.tplRaw,
      userPref: userPrefNext,
      clean: clean || nsOld.clean,
      gen: (gen && typeof gen === 'object') ? {
        temperature: Number.isFinite(+gen.temperature) ? +gen.temperature : undefined,
        top_p: Number.isFinite(+gen.top_p) ? +gen.top_p : undefined,
        top_k: Number.isFinite(+gen.top_k) ? +gen.top_k : undefined,
        presence_penalty: Number.isFinite(+gen.presence_penalty) ? +gen.presence_penalty : undefined,
        frequency_penalty: Number.isFinite(+gen.frequency_penalty) ? +gen.frequency_penalty : undefined
      } : (nsOld.gen || undefined)
    };
    if (typeof regexCombined === 'string') {
      const { pattern, flags } = parseCombinedRegex(regexCombined);
      new RegExp(pattern, flags);
      nsNext.extractRegex = `/${pattern}/${flags}`;
    }
    const props = {
      interval: Number.isFinite(+interval) && +interval>=0 ? +interval : 0,
      triggerTiming: timing || 'after_ai',
      floorType: floorType || 'all',
      disabled: !enabled,
      x: { ...(t.x||{}), LittleWhiteBox: nsNext }
    };
    await window.XBTasks.setProps(TASK_NAME, props, ref.scope);
    try {
      const pairedHit = window.XBTasks.find(PAIRED_TASK_NAME, ref.scope);
      if (pairedHit?.task) {
        const oldLBX = pairedHit.task?.x?.LittleWhiteBox || {};
        const nextLBX = { ...oldLBX, gen: nsNext.gen };
        await window.XBTasks.setProps(PAIRED_TASK_NAME, { x: { ...(pairedHit.task.x||{}), LittleWhiteBox: nextLBX } }, ref.scope);
      }
    } catch {}
    toastr?.success?.(`Đã lưu vào ${ref.scope==='preset'?'Preset':ref.scope==='character'?'Nhân vật':'Toàn cục'}：${TASK_NAME}`);
    window.dispatchEvent(new CustomEvent('xb:task:config_saved', { detail: { name: TASK_NAME, when: Date.now() } }));
  };
  const loadApiCfg = () => {
    const ref = getTaskRef();
    const t = ref?.task;
    const nsApi = t?.x?.LittleWhiteBox?.api || {};
    const apiState = (ex.apiByTask[TASK_NAME] ||= { provider:'st', url:'', key:'', model:'', enableNet:false, stream:true, cache:[] });
    return {
      provider: nsApi.provider || apiState.provider || 'st',
      url: nsApi.url || apiState.url || '',
      key: apiState.key || '',
      model: nsApi.model || apiState.model || '',
      enableNet: typeof nsApi.enableNet==='boolean' ? nsApi.enableNet : !!apiState.enableNet,
      stream: typeof nsApi.stream==='boolean' ? nsApi.stream : (apiState.stream ?? true),
      cache: Array.isArray(apiState.cache) ? apiState.cache.slice() : []
    };
  };
  const saveApiCfg = async (patch = {}) => {
    const apiState = (ex.apiByTask[TASK_NAME] ||= { provider:'st', url:'', key:'', model:'', enableNet:false, stream:true, cache:[] });
    const next = { ...apiState, ...patch };
    ex.apiByTask[TASK_NAME] = next;
    saveDebounced(); saveNow();
    const ref = getTaskRef();
    if (ref) {
      const nsOld = ref.task?.x?.LittleWhiteBox || {};
      const nextApi = { provider: next.provider || 'st', url: next.url || '', model: next.model || '', enableNet: !!next.enableNet, stream: typeof next.stream==='boolean' ? next.stream : true };
      await window.XBTasks.setProps(TASK_NAME, { x: { ...(ref.task.x||{}), LittleWhiteBox: { ...nsOld, api: nextApi } } }, ref.scope);
    }
  };

  const loadUserPrefStore = () => {
    const state = (ex.userPrefStoreByTask[TASK_NAME] ||= { selectedId: '', presets: [] });
    return {
      selectedId: String(state.selectedId || ''),
      presets: Array.isArray(state.presets) ? state.presets.map((p) => ({ ...p })) : []
    };
  };
  const saveUserPrefStore = (patch = {}) => {
    const state = (ex.userPrefStoreByTask[TASK_NAME] ||= { selectedId: '', presets: [] });
    const next = { ...state, ...patch };
    ex.userPrefStoreByTask[TASK_NAME] = next;
    saveDebounced(); saveNow();
    return next;
  };
  const PANEL_ID = 'xb_task_panel';
  const STYLE_ID = 'xb_taskui_styles';
  function injectStyles() {
    if ($(STYLE_ID)) return;
    const s = document.createElement('style');
    s.id = STYLE_ID;
    s.textContent = `
    /* Zen-iOS Hybrid Design System */
    #${PANEL_ID} {
        position: fixed; inset: 0; width: 100vw; height: 100svh; z-index: 10000;
        display: none; isolation: isolate; pointer-events: auto;
        font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
        color: #e5e5e5;
    }
    #${PANEL_ID} .mask {
        position: absolute; inset: 0;
        background: rgba(0,0,0,0.6);
        backdrop-filter: blur(4px);
    }
    #${PANEL_ID} .card {
        position: relative; width: 100vw; height: 100svh;
        background: rgba(30, 32, 36, 0.95);
        display: flex; flex-direction: column; overflow: hidden;
        box-sizing: border-box;
        padding-top: env(safe-area-inset-top);
        padding-bottom: env(safe-area-inset-bottom);
    }
    @media (min-width: 900px) {
        #${PANEL_ID} { display: flex; align-items: center; justify-content: center; }
        #${PANEL_ID} .card {
            width: 900px; height: 85vh;
            border-radius: 18px;
            border: 1px solid rgba(255,255,255,0.12);
            box-shadow: 0 40px 80px rgba(0,0,0,0.6);
        }
    }
    #${PANEL_ID} .head {
        display: flex; flex-direction: column; gap: 12px;
        padding: 16px 20px;
        background: rgba(255,255,255,0.03);
        border-bottom: 1px solid rgba(255,255,255,0.08);
        backdrop-filter: blur(10px);
        z-index: 10;
        flex: 0 0 auto;
        position: relative;
    }
    #${PANEL_ID} .head .title-row { display: flex; align-items: center; justify-content: space-between; gap: 12px; }
    #${PANEL_ID} .head .title-main { display: inline-flex; align-items: center; gap: 8px; }
    #${PANEL_ID} .head .title-row b { display: inline-flex; align-items: center; gap: 8px; font-size: 18px; font-weight: 600; letter-spacing: -0.5px; color: #fff; text-shadow: 0 2px 4px rgba(0,0,0,0.5); }
    #${PANEL_ID} .title-theme-toggle {
        appearance: none;
        -webkit-appearance: none;
        width: auto;
        height: auto;
        padding: 0;
        margin: 0;
        border: none;
        background: transparent;
        box-shadow: none;
